// Starfish LED Circuit
// 5 arms: Top, Top-Right, Bottom-Right, Bottom-Left, Top-Left
int pins[] = {9, 10, 11, 12, 13};

void setup() {
  for (int i = 0; i < 5; i++) {
    pinMode(pins[i], OUTPUT);
  }
}

// Ripple outward from center — one arm at a time (clockwise)
void ripple() {
  for (int i = 0; i < 5; i++) {
    digitalWrite(pins[i], HIGH);
    delay(150);
    digitalWrite(pins[i], LOW);
    delay(50);
  }
}

// All arms flash together
void allFlash(int times) {
  for (int t = 0; t < times; t++) {
    for (int i = 0; i < 5; i++) digitalWrite(pins[i], HIGH);
    delay(200);
    for (int i = 0; i < 5; i++) digitalWrite(pins[i], LOW);
    delay(200);
  }
}

// Twinkle: random arms blink
void twinkle() {
  for (int t = 0; t < 15; t++) {
    int arm = random(0, 5);
    digitalWrite(pins[arm], HIGH);
    delay(100);
    digitalWrite(pins[arm], LOW);
    delay(50);
  }
}

void loop() {
  ripple();       // Wave around the starfish arms
  ripple();
  ripple();
  allFlash(3);    // All arms flash 3 times
  twinkle();      // Random twinkling
  allFlash(2);    // Final flash
  delay(500);
}

